<template>
  <div class="black-bg" v-if="메뉴열렸냐 == true">
    <div class="white-bg">
      <button class="cancel" @click="메뉴열렸냐 = false">X</button>
    </div>
  </div>
  
  <div id="app">
    <header class="app-header">
      <h1 class="site-title">이것은 블로그다</h1>
      <h1 class="menuu" @click="메뉴열렸냐 = true">=</h1>
      <nav class="navbar">
        <router-link to="/" class="nav-link">홈</router-link>
        <router-link to="/create" class="nav-link">게시물 작성</router-link>
      </nav>
    </header>
    <router-view />
  </div>
</template>

<script>
 import axios from 'axios'

 const countryNames = {
  "US": "미국.",
  "KR": "자랑스러운 대한민국",
  "JP": "일본인임?",
  "GB": "와우 영국",
  // ... 더 많은 국가 코드와 이름 추가
 };

 export default {
   name: 'App',
   data() {
     return {
       userIp: null,
       userCun: null,
       메뉴열렸냐: false  // 사용자 IP 주소를 저장할 변수
     };
   },
   mounted() {
     this.fetchUserIp();
    
   },
   methods: {
     async fetchUserIp() {
       try {
         const response = await axios.get('https://ipinfo.io/json');  
         this.userIp = response.data.ip;  
         const countryCode = response.data.country;
         this.userCun = countryNames[countryCode] || "Unknown";  // 국가 이름으로 변환
       } catch (error) {
           console.error("IP 주소를 가져오는 데 오류가 발생했습니다:", error);
       }
     }
   }
 };
</script>

