<template>
  <div class="comment-section">
    <h3>댓글</h3>

    <!-- 댓글 입력 폼 -->
    <div>
      <input v-model="user" placeholder="이름을 입력하세요" />
      <input v-model="newComment" placeholder="댓글을 입력하세요" />
      <button @click="submitComment">댓글 작성</button>
    </div>


    <!-- 댓글 목록 -->
    <div v-if="comments.length > 0">
      <ul>
        <li v-for="comment in comments" :key="comment.id">
          <strong>{{ comment.userName }}</strong> <br> {{ comment.text }}
          <button @click="deleteComment(comment.id)">삭제</button>
        </li>
      </ul>
    </div>
    <div v-else>
      <p>아직 댓글이 없습니다.</p>
    </div>
  </div>
</template>

<script>
import { addComment, getComments, deleteComment } from "../firebase"; // Firebase에서 댓글 관련 함수 import

export default {
  data() {
    return {
      newComment: '', // 새 댓글 텍스트
      comments: [], // 댓글 목록
      user: '', // 로그인된 사용자 정보 (예시로 null로 두고 실제로는 로그인 상태에 맞게 처리)
      postId: "examplePostId", // 게시물 ID (이 부분은 실제로 어떤 게시물에 달린 댓글인지 나타내는 값)
    };
  },
  created() {
    // 페이지가 로드되면 댓글 목록을 가져옵니다.
    this.fetchComments();

    
  },
  methods: {
    // 댓글 추가
    async submitComment() {
      if (!this.newComment.trim()) return; // 댓글이 비어있지 않으면 작성

      // 댓글을 Firestore에 추가
      await addComment(this.newComment, this.user, this.postId);

      // 댓글 입력 필드 초기화
      this.newComment = '';

      this.user = '';

      // 댓글 목록을 다시 불러옴
      this.fetchComments();
    },

    // 댓글 목록 조회
    async fetchComments() {
      // 해당 게시물에 달린 댓글을 가져옴
      this.comments = await getComments(this.postId);
    },

    // 댓글 삭제
    async deleteComment(commentId) {
      await deleteComment(commentId);

      // 댓글 목록을 다시 불러옴
      this.fetchComments();
    },
  },
};
</script>

<style scoped>
.comment-section {
  margin-top: 20px;
}

input {
  width: 100%;
  padding: 10px;
  margin-bottom: 10px;
}

button {
  padding: 10px;
}

ul {
  list-style-type: none;
  padding: 0;
}

li {
  margin-bottom: 10px;
}

strong {
  color: #007BFF;
  font-size: 15px;
}
</style>
