// Firebase 초기화
const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// 댓글 관련 함수들
export const addComment = async (commentText, userName, postId) => {
  const commentsCollectionRef = collection(db, "comments");

  try {
    // 댓글 추가
    await addDoc(commentsCollectionRef, {
      text: commentText,
      userName: userName,
      timestamp: serverTimestamp(), // 서버에서 자동으로 현재 시간 추가
      postId: postId,
    });

    console.log("댓글이 추가되었습니다!");
  } catch (error) {
    console.error("댓글 추가 실패:", error);
  }
};

export const getComments = async (postId) => {
  const commentsCollectionRef = collection(db, "comments");

  try {
    // 특정 게시물(postId)에 대한 댓글만 조회
    const q = query(commentsCollectionRef, where("postId", "==", postId));
    const querySnapshot = await getDocs(q);

    const comments = querySnapshot.docs.map(doc => ({
      id: doc.id, // Firestore 문서 ID
      ...doc.data(),
    }));

    return comments;
  } catch (error) {
    console.error("댓글 조회 실패:", error);
  }
};

export const deleteComment = async (commentId) => {
  const commentDocRef = doc(db, "comments", commentId);

  try {
    await deleteDoc(commentDocRef);
    console.log("댓글이 삭제되었습니다!");
  } catch (error) {
    console.error("댓글 삭제 실패:", error);
  }
};

// Firestore에서 댓글 읽기 및 추가 기능을 export
export { db, collection, getDocs, addDoc, doc, deleteDoc, getDoc };
